	r.Body = http.MaxBytesReader(w, r.Body, maxPayloadBytes+2048)

	raw, err := io.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Failed to read request", http.StatusBadRequest)
		return
	}

	result, err := p.ProcessTask(r.Context(), raw)
	if err != nil {
		log.Printf("Task processing failed from %s: %v", r.RemoteAddr, err)
